import { Convert } from 'pvtsutils';
import { ActivityDescriptionAttribute } from './activity_description_attribute';

describe('ActivityDescriptionAttribute', () => {
  it('should return correct JSON structure', () => {
    /**
     * Name: Activity Description
     * Code Authority: RFC 822 Name: NACEBEL
     * Code ID: RFC 822 Name: 66.010
     * Short Name: Computer programming activities
     * Short Description: La société a pour objet le développement...
     */
    const hexAttribute = '';
    const attribute = new ActivityDescriptionAttribute(Convert.FromHex(hexAttribute));

    const json = attribute.toJSON();

    expect(json).toMatchSnapshot();
  });
});
